class Solution {
public:
    long long countMajoritySubarrays(vector<int>& nums, int target) {
        int n = nums.size();
        vector<int> freq(2 * n + 1, 0);
        freq[n] = 1;
        int idx = n;
        long long res = 0;
        long long pref = 0;
        for (int x : nums) {
            if (x == target) {
                pref += freq[idx];
                idx++;
            } else {
                idx--;
                pref -= freq[idx];
            }
            freq[idx]++;
            res += pref;
        }
        return res;
    }
};

class Solution {
public:
    bool isOneBitCharacter(vector<int>& bits) {
        int i = 0;
        int n = bits.size();

        while (i < n - 1) {
            if (bits[i] == 0)
                i += 1;
            else
                i += 2;
        }

        return i == n - 1;
    }
};

class Solution {
public:
    int reverse(int x) {
        int rev = 0;

        while (x != 0) {
            int digit = x % 10;

            // Positive overflow
            if (rev > INT_MAX / 10 || (rev == INT_MAX / 10 && digit > 7))
                return 0;
            if (rev < INT_MIN / 10 || (rev == INT_MIN / 10 && digit < -8))
                return 0;

            rev = rev * 10 + digit;
            x /= 10;
        }

        return rev;
    }
};

